<template>
  <div class="data-resource-config">
    <el-page-header title="返回" @back="goBack">
      <template #content>
        <h2>数据资源配置</h2>
      </template>
      <template #extra>
        <el-button type="primary" @click="showAddDialog">
          <el-icon><Plus /></el-icon> 添加数据源
        </el-button>
      </template>
    </el-page-header>

    <el-card class="filter-card">
      <el-form :inline="true" :model="filterForm">
        <el-form-item label="搜索数据源">
          <el-input v-model="filterForm.keyword" placeholder="输入数据源名称"></el-input>
        </el-form-item>
        <el-form-item label="类型">
          <el-select v-model="filterForm.type" placeholder="所有类型">
            <el-option label="Excel" value="Excel"></el-option>
            <el-option label="MySQL" value="MySQL"></el-option>
            <el-option label="XML" value="XML"></el-option>
            <el-option label="JSON" value="JSON"></el-option>
            <el-option label="CSV" value="CSV"></el-option>
          </el-select>
        </el-form-item>
        <el-form-item>
          <el-button type="primary" @click="searchDataSources">搜索</el-button>
        </el-form-item>
      </el-form>
    </el-card>

    <el-card>
      <template #header>
        <div class="card-header">
          <span>数据源列表</span>
          <div>
            <el-tag type="info">总计: {{ dataSources.length }}</el-tag>
          </div>
        </div>
      </template>

      <el-table :data="paginatedDataSources" style="width: 100%">
        <el-table-column prop="name" label="数据源名称"></el-table-column>
        <el-table-column prop="type" label="类型">
          <template #default="{ row }">
            <el-tag :type="getTypeTagType(row.type)">
              {{ row.type }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="path" label="文件路径/连接信息"></el-table-column>
        <el-table-column prop="sheet" label="工作表/表名" v-if="hasSheetOrTableColumn"></el-table-column>
        <el-table-column label="操作" width="200">
          <template #default="{ row }">
            <el-button size="small" @click="editDataSource(row)">编辑</el-button>
            <el-button size="small" type="danger" @click="confirmDelete(row)">删除</el-button>
          </template>
        </el-table-column>
      </el-table>

      <el-pagination
        class="pagination"
        v-model:current-page="currentPage"
        v-model:page-size="pageSize"
        :page-sizes="[10, 20, 30, 50]"
        layout="total, sizes, prev, pager, next, jumper"
        :total="filteredDataSources.length"
      />
    </el-card>

    <!-- 添加/编辑数据源对话框 -->
    <el-dialog v-model="dataSourceDialogVisible" :title="isEdit ? '编辑数据源' : '添加数据源'" width="50%">
      <div class="data-source-type-selection" v-if="!isEdit">
        <h3>数据源类型</h3>
        <el-radio-group v-model="selectedType" class="data-source-type-group">
          <el-radio-button label="Excel">
            <el-icon><Document /></el-icon> Excel 电子表格
          </el-radio-button>
          <el-radio-button label="MySQL">
            <el-icon><Platform /></el-icon> MySQL 数据库
          </el-radio-button>
          <el-radio-button label="XML">
            <el-icon><Document /></el-icon> XML 文件
          </el-radio-button>
          <el-radio-button label="JSON">
            <el-icon><Document /></el-icon> JSON 文件
          </el-radio-button>
          <el-radio-button label="CSV">
            <el-icon><Document /></el-icon> CSV 文件
          </el-radio-button>
        </el-radio-group>
      </div>

      <!-- Excel表格配置 -->
      <div v-if="selectedType === 'Excel' || (isEdit && dataSourceForm.type === 'Excel')">
        <h3>Excel 数据源配置</h3>
        <el-form :model="dataSourceForm" label-width="120px">
          <el-form-item label="数据源名称" required>
            <el-input v-model="dataSourceForm.name" placeholder="请输入数据源名称"></el-input>
          </el-form-item>
          <el-form-item label="文件路径" required>
            <el-input v-model="dataSourceForm.path" placeholder="选择Excel文件">
              <template #append>
                <el-button @click="openFileBrowser('excel')">浏览</el-button>
              </template>
            </el-input>
          </el-form-item>
          <el-form-item label="工作表">
            <el-select v-model="dataSourceForm.sheet" placeholder="选择工作表">
              <el-option v-for="sheet in availableSheets" :key="sheet" :label="sheet" :value="sheet"></el-option>
            </el-select>
          </el-form-item>
        </el-form>

        <!-- 预览数据 -->
        <div class="preview-data" v-if="dataSourceForm.path && dataSourceForm.sheet">
          <h3>预览数据</h3>
          <el-table :data="previewData" style="width: 100%">
            <el-table-column v-for="col in previewColumns" :key="col.prop" :prop="col.prop" :label="col.label"></el-table-column>
          </el-table>
        </div>
      </div>

      <!-- MySQL数据库配置 -->
      <div v-if="selectedType === 'MySQL' || (isEdit && dataSourceForm.type === 'MySQL')">
        <h3>MySQL 数据库配置</h3>
        <el-form :model="dataSourceForm" label-width="120px">
          <el-form-item label="数据源名称" required>
            <el-input v-model="dataSourceForm.name" placeholder="请输入数据源名称"></el-input>
          </el-form-item>
          <el-form-item label="主机地址" required>
            <el-input v-model="dataSourceForm.host" placeholder="例如: localhost"></el-input>
          </el-form-item>
          <el-form-item label="端口" required>
            <el-input v-model="dataSourceForm.port" placeholder="例如: 3306"></el-input>
          </el-form-item>
          <el-form-item label="数据库名称" required>
            <el-input v-model="dataSourceForm.database" placeholder="输入数据库名称"></el-input>
          </el-form-item>
          <el-form-item label="用户名" required>
            <el-input v-model="dataSourceForm.username" placeholder="输入用户名"></el-input>
          </el-form-item>
          <el-form-item label="密码" required>
            <el-input v-model="dataSourceForm.password" type="password" placeholder="输入密码"></el-input>
          </el-form-item>
          <el-form-item label="表名">
            <el-select v-model="dataSourceForm.table" placeholder="选择表" filterable>
              <el-option v-for="table in availableTables" :key="table" :label="table" :value="table"></el-option>
            </el-select>
            <el-button class="connect-btn" type="primary" @click="testConnection">测试连接</el-button>
          </el-form-item>
        </el-form>

        <!-- 预览数据 -->
        <div class="preview-data" v-if="dataSourceForm.table && mysqlConnectionStatus === 'success'">
          <h3>预览数据</h3>
          <el-table :data="previewData" style="width: 100%">
            <el-table-column v-for="col in previewColumns" :key="col.prop" :prop="col.prop" :label="col.label"></el-table-column>
          </el-table>
        </div>
      </div>

      <!-- XML文件配置 -->
      <div v-if="selectedType === 'XML' || (isEdit && dataSourceForm.type === 'XML')">
        <h3>XML 文件配置</h3>
        <el-form :model="dataSourceForm" label-width="120px">
          <el-form-item label="数据源名称" required>
            <el-input v-model="dataSourceForm.name" placeholder="请输入数据源名称"></el-input>
          </el-form-item>
          <el-form-item label="文件路径" required>
            <el-input v-model="dataSourceForm.path" placeholder="选择XML文件">
              <template #append>
                <el-button @click="openFileBrowser('xml')">浏览</el-button>
              </template>
            </el-input>
          </el-form-item>
          <el-form-item label="根节点路径">
            <el-input v-model="dataSourceForm.rootPath" placeholder="例如: /root/items"></el-input>
          </el-form-item>
        </el-form>

        <!-- 预览数据 -->
        <div class="preview-data" v-if="dataSourceForm.path">
          <h3>预览数据</h3>
          <el-table :data="previewData" style="width: 100%">
            <el-table-column v-for="col in previewColumns" :key="col.prop" :prop="col.prop" :label="col.label"></el-table-column>
          </el-table>
        </div>
      </div>

      <!-- JSON文件配置 -->
      <div v-if="selectedType === 'JSON' || (isEdit && dataSourceForm.type === 'JSON')">
        <h3>JSON 文件配置</h3>
        <el-form :model="dataSourceForm" label-width="120px">
          <el-form-item label="数据源名称" required>
            <el-input v-model="dataSourceForm.name" placeholder="请输入数据源名称"></el-input>
          </el-form-item>
          <el-form-item label="文件路径" required>
            <el-input v-model="dataSourceForm.path" placeholder="选择JSON文件">
              <template #append>
                <el-button @click="openFileBrowser('json')">浏览</el-button>
              </template>
            </el-input>
          </el-form-item>
          <el-form-item label="数据路径">
            <el-input v-model="dataSourceForm.dataPath" placeholder="例如: data.items"></el-input>
          </el-form-item>
        </el-form>

        <!-- 预览数据 -->
        <div class="preview-data" v-if="dataSourceForm.path">
          <h3>预览数据</h3>
          <el-table :data="previewData" style="width: 100%">
            <el-table-column v-for="col in previewColumns" :key="col.prop" :prop="col.prop" :label="col.label"></el-table-column>
          </el-table>
        </div>
      </div>

      <!-- CSV文件配置 -->
      <div v-if="selectedType === 'CSV' || (isEdit && dataSourceForm.type === 'CSV')">
        <h3>CSV 文件配置</h3>
        <el-form :model="dataSourceForm" label-width="120px">
          <el-form-item label="数据源名称" required>
            <el-input v-model="dataSourceForm.name" placeholder="请输入数据源名称"></el-input>
          </el-form-item>
          <el-form-item label="文件路径" required>
            <el-input v-model="dataSourceForm.path" placeholder="选择CSV文件">
              <template #append>
                <el-button @click="openFileBrowser('csv')">浏览</el-button>
              </template>
            </el-input>
          </el-form-item>
          <el-form-item label="分隔符">
            <el-select v-model="dataSourceForm.delimiter" placeholder="选择分隔符">
              <el-option label="逗号(,)" value=","></el-option>
              <el-option label="分号(;)" value=";"></el-option>
              <el-option label="制表符(Tab)" value="\t"></el-option>
              <el-option label="竖线(|)" value="|"></el-option>
            </el-select>
          </el-form-item>
          <el-form-item label="包含表头">
            <el-switch v-model="dataSourceForm.hasHeader"></el-switch>
          </el-form-item>
        </el-form>

        <!-- 预览数据 -->
        <div class="preview-data" v-if="dataSourceForm.path">
          <h3>预览数据</h3>
          <el-table :data="previewData" style="width: 100%">
            <el-table-column v-for="col in previewColumns" :key="col.prop" :prop="col.prop" :label="col.label"></el-table-column>
          </el-table>
        </div>
      </div>

      <template #footer>
        <span class="dialog-footer">
          <el-button @click="dataSourceDialogVisible = false">取消</el-button>
          <el-button type="danger" @click="deleteDataSource" v-if="isEdit">删除数据源</el-button>
          <el-button type="primary" @click="submitDataSource">{{ isEdit ? '保存配置' : '保存配置' }}</el-button>
        </span>
      </template>
    </el-dialog>

    <!-- 删除确认对话框 -->
    <el-dialog v-model="deleteConfirmVisible" title="确认删除" width="30%">
      <p>确定要删除数据源 "{{ currentDataSource?.name }}" 吗？此操作不可恢复。</p>
      <template #footer>
        <span class="dialog-footer">
          <el-button @click="deleteConfirmVisible = false">取消</el-button>
          <el-button type="danger" @click="deleteDataSource">确认删除</el-button>
        </span>
      </template>
    </el-dialog>

    <!-- 我们不需要文件浏览器对话框，因为我们使用原生文件选择器 -->

    <!-- MySQL连接测试结果提示 -->
    <el-dialog v-model="mysqlTestResultVisible" :title="mysqlTestResult.success ? '连接成功' : '连接失败'" width="30%">
      <p>{{ mysqlTestResult.message }}</p>
      <template #footer>
        <span class="dialog-footer">
          <el-button @click="mysqlTestResultVisible = false">确定</el-button>
        </span>
      </template>
    </el-dialog>
  </div>
</template>

<script setup>
import { ref, computed, reactive, watch, onMounted } from 'vue'
import { useRouter } from 'vue-router'
import { useStore } from 'vuex'
import { Plus, Document, Platform, Folder } from '@element-plus/icons-vue'
import { ElMessage, ElLoading } from 'element-plus'

const router = useRouter()
const store = useStore()

// 表单数据
const filterForm = ref({
  keyword: '',
  type: ''
})

// 分页相关
const currentPage = ref(1)
const pageSize = ref(10)

// 对话框控制
const dataSourceDialogVisible = ref(false)
const deleteConfirmVisible = ref(false)
const mysqlTestResultVisible = ref(false)
const isEdit = ref(false)
const selectedType = ref('Excel')

// MySQL连接测试结果
const mysqlTestResult = ref({
  success: false,
  message: ''
})
const mysqlConnectionStatus = ref('') // 'success', 'error', 'loading', ''

// 数据源表单 - 使用reactive以支持不同类型的表单字段
const dataSourceForm = reactive({
  id: null,
  name: '',
  type: 'Excel',
  path: '',
  // Excel特有
  sheet: '',
  // MySQL特有
  host: 'localhost',
  port: '3306',
  database: '',
  username: '',
  password: '',
  table: '',
  // XML特有
  rootPath: '',
  // JSON特有
  dataPath: '',
  // CSV特有
  delimiter: ',',
  hasHeader: true
})

// 当前操作的数据源
const currentDataSource = ref(null)

// 可用的工作表/表名
const availableSheets = ref(['Projects', 'Bugs', 'TestCases'])
const availableTables = ref([])

// 文件浏览器相关
const currentPath = ref('/')
const fileList = ref([
  { name: 'Documents', isDirectory: true, type: '文件夹', size: '-', lastModified: '2023-05-15 10:30' },
  { name: 'Downloads', isDirectory: true, type: '文件夹', size: '-', lastModified: '2023-05-14 15:45' },
  { name: 'data', isDirectory: true, type: '文件夹', size: '-', lastModified: '2023-05-10 09:20' },
  { name: 'report.xlsx', isDirectory: false, type: 'Excel', size: '1.2 MB', lastModified: '2023-05-01 14:10' },
  { name: 'config.json', isDirectory: false, type: 'JSON', size: '4.5 KB', lastModified: '2023-04-28 16:25' },
  { name: 'data.xml', isDirectory: false, type: 'XML', size: '8.7 KB', lastModified: '2023-04-22 11:30' },
  { name: 'users.csv', isDirectory: false, type: 'CSV', size: '2.1 MB', lastModified: '2023-04-15 09:45' }
])
const selectedFile = ref(null)

// 预览数据
const previewData = ref([
  { id: 1, name: 'Chart', language: 'Java', bugs: 26 },
  { id: 2, name: 'Math', language: 'Java', bugs: 106 },
  { id: 3, name: 'Time', language: 'Java', bugs: 27 }
])

// 预览列
const previewColumns = ref([
  { prop: 'id', label: 'ID' },
  { prop: 'name', label: '项目名称' },
  { prop: 'language', label: '语言' },
  { prop: 'bugs', label: '缺陷数' }
])

// 从store获取数据源
const dataSources = computed(() => store.state.dataSources || [])

// 是否显示工作表/表名列
const hasSheetOrTableColumn = computed(() => {
  return dataSources.value.some(ds => 
    ds.type === 'Excel' || 
    ds.type === 'MySQL'
  )
})

// 过滤后的数据源
const filteredDataSources = computed(() => {
  return dataSources.value.filter(dataSource => {
    const matchesKeyword = dataSource.name.toLowerCase().includes(filterForm.value.keyword.toLowerCase())
    const matchesType = filterForm.value.type ? 
      dataSource.type === filterForm.value.type : true
    return matchesKeyword && matchesType
  })
})

// 分页后的数据源
const paginatedDataSources = computed(() => {
  const start = (currentPage.value - 1) * pageSize.value
  const end = start + pageSize.value
  return filteredDataSources.value.slice(start, end)
})

// 当前路径的各个部分
const currentPathParts = computed(() => {
  return currentPath.value.split('/').filter(part => part !== '')
})

// 监听selectedType的变化
watch(() => selectedType.value, (newType) => {
  // 根据选择的类型初始化dataSourceForm
  dataSourceForm.type = newType
  
  if (newType === 'Excel') {
    dataSourceForm.sheet = 'Projects'
  } else if (newType === 'MySQL') {
    // 初始化MySQL特有的字段
    dataSourceForm.host = 'localhost'
    dataSourceForm.port = '3306'
    dataSourceForm.database = ''
    dataSourceForm.username = ''
    dataSourceForm.password = ''
    dataSourceForm.table = ''
  } else if (newType === 'CSV') {
    // 初始化CSV特有的字段
    dataSourceForm.delimiter = ','
    dataSourceForm.hasHeader = true
  }
})

// 根据类型获取标签样式
function getTypeTagType(type) {
  const typeMap = {
    'Excel': '',
    'MySQL': 'info',
    'XML': 'success',
    'JSON': 'warning',
    'CSV': 'danger'
  }
  return typeMap[type] || 'info'
}

// 返回上一页
function goBack() {
  router.go(-1)
}

// 显示添加对话框
function showAddDialog() {
  isEdit.value = false
  selectedType.value = 'Excel'
  Object.assign(dataSourceForm, {
    id: null,
    name: '',
    type: 'Excel',
    path: '',
    sheet: 'Projects',
    host: 'localhost',
    port: '3306',
    database: '',
    username: '',
    password: '',
    table: '',
    rootPath: '',
    dataPath: '',
    delimiter: ',',
    hasHeader: true
  })
  dataSourceDialogVisible.value = true
}

// 编辑数据源
function editDataSource(dataSource) {
  isEdit.value = true
  currentDataSource.value = dataSource
  selectedType.value = dataSource.type
  
  // 确保表单初始化为适合当前类型的字段
  Object.assign(dataSourceForm, {
    id: dataSource.id,
    name: dataSource.name,
    type: dataSource.type,
    path: dataSource.path,
    sheet: dataSource.sheet || 'Projects',
    host: dataSource.host || 'localhost',
    port: dataSource.port || '3306',
    database: dataSource.database || '',
    username: dataSource.username || '',
    password: dataSource.password || '',
    table: dataSource.table || '',
    rootPath: dataSource.rootPath || '',
    dataPath: dataSource.dataPath || '',
    delimiter: dataSource.delimiter || ',',
    hasHeader: dataSource.hasHeader !== undefined ? dataSource.hasHeader : true
  })
  
  // 如果是MySQL类型，获取可用的表
  if (dataSource.type === 'MySQL' && 
      dataSource.host && 
      dataSource.database && 
      dataSource.username) {
    fetchAvailableTables()
  }
  
  dataSourceDialogVisible.value = true
}

// 确认删除
function confirmDelete(dataSource) {
  currentDataSource.value = dataSource
  deleteConfirmVisible.value = true
}

// 删除数据源
function deleteDataSource() {
  if (currentDataSource.value) {
    // 这里应该调用API删除数据源
    // 在实际项目中会有一个mutation来处理删除
    const index = dataSources.value.findIndex(ds => ds.id === currentDataSource.value.id)
    if (index !== -1) {
      // 模拟删除
      store.commit('removeDataSource', currentDataSource.value.id)
      ElMessage.success('数据源删除成功')
    }
  }
  deleteConfirmVisible.value = false
  dataSourceDialogVisible.value = false
}

// 提交数据源表单
function submitDataSource() {
  // 基本验证
  if (!dataSourceForm.name) {
    ElMessage.warning('请输入数据源名称')
    return
  }
  
  if (dataSourceForm.type === 'Excel' || 
      dataSourceForm.type === 'XML' || 
      dataSourceForm.type === 'JSON' || 
      dataSourceForm.type === 'CSV') {
    if (!dataSourceForm.path) {
      ElMessage.warning(`请选择${dataSourceForm.type}文件`)
      return
    }
  } else if (dataSourceForm.type === 'MySQL') {
    if (!dataSourceForm.host || !dataSourceForm.database || !dataSourceForm.username) {
      ElMessage.warning('请填写MySQL连接信息')
      return
    }
  }
  
  // 准备保存的数据源对象
  const saveDataSource = {
    id: dataSourceForm.id,
    name: dataSourceForm.name,
    type: dataSourceForm.type,
    path: dataSourceForm.path
  }
  
  // 根据类型添加特定字段
  if (dataSourceForm.type === 'Excel') {
    saveDataSource.sheet = dataSourceForm.sheet
  } else if (dataSourceForm.type === 'MySQL') {
    saveDataSource.host = dataSourceForm.host
    saveDataSource.port = dataSourceForm.port
    saveDataSource.database = dataSourceForm.database
    saveDataSource.username = dataSourceForm.username
    saveDataSource.password = dataSourceForm.password
    saveDataSource.table = dataSourceForm.table
  } else if (dataSourceForm.type === 'XML') {
    saveDataSource.rootPath = dataSourceForm.rootPath
  } else if (dataSourceForm.type === 'JSON') {
    saveDataSource.dataPath = dataSourceForm.dataPath
  } else if (dataSourceForm.type === 'CSV') {
    saveDataSource.delimiter = dataSourceForm.delimiter
    saveDataSource.hasHeader = dataSourceForm.hasHeader
  }
  
  if (isEdit.value) {
    // 更新现有数据源
    store.commit('updateDataSource', saveDataSource)
    ElMessage.success('数据源更新成功')
  } else {
    // 添加新数据源
    saveDataSource.id = dataSources.value.length > 0 ? 
      Math.max(...dataSources.value.map(ds => ds.id)) + 1 : 1
    store.commit('addDataSource', saveDataSource)
    ElMessage.success('数据源添加成功')
  }
  
  dataSourceDialogVisible.value = false
}

// 搜索数据源
function searchDataSources() {
  // 实际项目中可能会调用API
  console.log('Search with:', filterForm.value)
  // 重置分页到第一页
  currentPage.value = 1
}

// 打开文件浏览器（使用原生文件选择器）
function openFileBrowser(fileType) {
  // 创建一个隐藏的文件输入框
  const fileInput = document.createElement('input')
  fileInput.type = 'file'
  
  // 根据文件类型设置接受的文件扩展名
  switch(fileType) {
    case 'excel':
      fileInput.accept = '.xlsx,.xls,.xlsm'
      break
    case 'xml':
      fileInput.accept = '.xml'
      break
    case 'json':
      fileInput.accept = '.json'
      break
    case 'csv':
      fileInput.accept = '.csv'
      break
    default:
      fileInput.accept = '*'
  }
  
  // 文件选择事件处理
  fileInput.onchange = (event) => {
    const file = event.target.files[0]
    if (file) {
      // 设置文件路径到表单
      dataSourceForm.path = file.name // 实际应用中可能需要完整路径
      
      // 根据文件类型更新预览数据
      if (fileType === 'excel') {
        // 模拟获取Excel工作表
        setTimeout(() => {
          availableSheets.value = ['Projects', 'Bugs', 'TestCases', 'TestResults']
          dataSourceForm.sheet = availableSheets.value[0]
          updatePreviewData()
        }, 500)
      } else {
        updatePreviewData()
      }
      
      ElMessage.success(`已选择文件: ${file.name}`)
    }
  }
  
  // 触发文件选择对话框
  fileInput.click()
}

// 更新文件列表
function updateFileList() {
    
  // 在实际项目中，这里应该调用API获取当前路径下的文件和文件夹
  // 这里使用模拟数据
  
  // 如果当前路径不是根目录，添加返回上级目录的选项
  if (currentPath.value !== '/') {
    fileList.value = [
      { name: '..', isDirectory: true, type: '上级目录', size: '-', lastModified: '-' },
      // 模拟不同目录下有不同的文件
      { name: 'document.xlsx', isDirectory: false, type: 'Excel', size: '2.3 MB', lastModified: '2023-06-10 14:25' },
      { name: 'config.xml', isDirectory: false, type: 'XML', size: '5.2 KB', lastModified: '2023-06-08 10:15' }
    ]
  } else {
    // 根目录文件列表
    fileList.value = [
      { name: 'Documents', isDirectory: true, type: '文件夹', size: '-', lastModified: '2023-05-15 10:30' },
      { name: 'Downloads', isDirectory: true, type: '文件夹', size: '-', lastModified: '2023-05-14 15:45' },
      { name: 'data', isDirectory: true, type: '文件夹', size: '-', lastModified: '2023-05-10 09:20' },
      { name: 'report.xlsx', isDirectory: false, type: 'Excel', size: '1.2 MB', lastModified: '2023-05-01 14:10' },
      { name: 'config.json', isDirectory: false, type: 'JSON', size: '4.5 KB', lastModified: '2023-04-28 16:25' },
      { name: 'data.xml', isDirectory: false, type: 'XML', size: '8.7 KB', lastModified: '2023-04-22 11:30' },
      { name: 'users.csv', isDirectory: false, type: 'CSV', size: '2.1 MB', lastModified: '2023-04-15 09:45' }
    ]
  }
  
  // 根据当前选择的文件类型过滤
  if (currentFileBrowserType.value !== '') {
    // 保留所有文件夹和匹配类型的文件
    fileList.value = fileList.value.filter(file => 
      file.isDirectory || 
      file.type.toLowerCase() === currentFileBrowserType.value.toLowerCase()
    )
  }
}

